BASE_URL = "https://staging.channex.io/api/v1"
if not env.company.x_channex_api_key:
    raise UserError("Channex API key is missing in company settings.")
try:
    method, endpoint = env.context.get('method'), env.context.get('endpoint')
    if not method or method not in ["GET", "POST", "PUT", "DELETE"]:
        raise UserError("Http request to channex cannot be sent because method is invalid")
    if not endpoint:
        raise UserError("Http request to channex cannot be sent because endpoint is empty")
    response = requests.request(
        method=method,
        url=f"{BASE_URL}/{endpoint}",
        data=json.dumps(env.context.get('payload', {})),
        timeout=20, headers={
            'Content-Type': 'application/json',
            'user-api-key': env.company.x_channex_api_key
        }
    )
    response.raise_for_status()
    action = response.json()
except Exception as e:
    raise UserError(f"Channex API error: {str(e)}")

