def construct_availability_payload(property_id, room_type_id, records, ota_buffer):
    room_payload = []

    if not records:
        return room_payload

    current_start = current_end = records[0].x_date
    current_qty = records[0].x_available

    for rec in records[1:]:

        if rec.x_available != current_qty:
            room_payload.append({
                'property_id': property_id,
                'room_type_id': room_type_id,
                'date_from': current_start.strftime('%Y-%m-%d'),
                'date_to': current_end.strftime('%Y-%m-%d'),
                'availability': min(0, current_qty - ota_buffer),
            })

            current_start = current_end = rec.x_date
            current_qty = rec.x_available
        else:
            current_end = rec.x_date

    room_payload.append({
        'property_id': property_id,
        'room_type_id': room_type_id,
        'date_from': current_start.strftime('%Y-%m-%d'),
        'date_to': current_end.strftime('%Y-%m-%d'),
        'availability': min(0, current_qty - ota_buffer),
    })

    return room_payload

