def create_on_channex(endpoint, payload, mapping, error_msg):
    try:
        data = env.ref('booking_channex.requests_to_channex').with_context(method="POST", endpoint=endpoint, payload=payload).run()
        remote_id = data.json().get('data', {}).get('attributes', {}).get('id')

        if not remote_id:
            raise UserError(f"{error_msg}: Invalid response from Channex")

        mapping.write({'x_remote_id': remote_id})

    except Exception as e:
        raise UserError(f"{error_msg}: {str(e)}")

