            to_add_rate_plans.append(rate_plan.id)

for rate_plan in odoo_rates_mapping:
    if channex_dict := channex_rate_plans_by_id.get(odoo_rates_mapping[rate_plan]).get("attributes"):
        if rate_plan.x_name != channex_dict.get("title"): #Name contains pricelist and rate plan corresponding
            rate_plans_to_update.append(rate_plan.id)

env.ref('booking_channex.update_rate_plan_on_channex').with_context(active_ids=rate_plans_to_update, active_model="x_rate_plan", rates_odoo_to_channex=rate_plans_matching).run()
for rate_plan_channex_id in to_remove_rate_plans:
    env.ref('booking_channex.requests_to_channex').with_context(method="DELETE", endpoint="rate_plans/%s" % rate_plan_channex_id).run()

self.env['ir.cron']._commit_progress(remaining=4)

#ROOMS
all_channex_rooms = env.ref('booking_channex.requests_to_channex').with_context(
    method="GET", endpoint="room_types"
).run().json().get('data', {})

channex_rooms_by_id = {room.get("id"): room for room in all_channex_rooms}
channex_rooms_mapping = {}
odoo_rooms_mapping = {}
for room_map in env['x_channex_mapping'].search([('x_model_type', '=', 'room_type')]):
    room_record = env.browse(room_map.x_local_id)
    channex_rooms_mapping[room_map.x_remote_id] = room_record
    odoo_rooms_mapping[room_record] = room_map.x_remote_id

for el in channex_rooms_by_id.values():
    if not (el.get("id") and (room_record := channex_rooms_mapping.get(el.get("id")))):
        to_remove_rooms.append(el.get("id"))

for room in env['product.product'].search([('x_is_a_room_offer', '=', True), ('x_resource_ids', '!=', False)]):
    if room_remote_id := odoo_rooms_mapping.get(room):
        if not (room_remote_id and (el := channex_rooms_by_id.get(room_remote_id))):
            to_add_rooms.append(room.id)

for room in odoo_rooms_mapping:
    if channex_dict := channex_rooms_by_id.get(odoo_rooms_mapping[room]).get("attributes"):
        if room.display_name != channex_dict.get("title") or len(room.x_resource_ids) != channex_dict.get("count_of_rooms"):
            rooms_to_update.append(room.id)

env.ref('booking_channex.update_room_on_channex').with_context(active_ids=rooms_to_update, active_model="product.product", rooms_odoo_to_channex=rooms_matching).run()
for room_channex_id in to_remove_rooms:
    env.ref('booking_channex.requests_to_channex').with_context(method="DELETE", endpoint="room_type/%s" % room_channex_id).run()

self.env['ir.cron']._commit_progress(remaining=3)

#PROPERTIES
all_channex_properties = env.ref('booking_channex.requests_to_channex').with_context(
    method="GET", endpoint="properties"
).run().json().get('data', {})

channex_properties_by_id = {property.get("id"): property for property in all_channex_properties}
channex_properties_mapping = {}
odoo_properties_mapping = {}
for property_map in env['x_channex_mapping'].search([('x_model_type', '=', 'property')]):
    property_record = env.browse(property_map.x_local_id)
    channex_properties_mapping[property_map.x_remote_id] = property_record
    odoo_properties_mapping[property_record] = property_map.x_remote_id

for el in channex_properties_by_id.values():
    if not (el.get("id") and (property_record := channex_properties_mapping.get(el.get("id")))):
        to_remove_properties.append(el.get("id"))

for property in env.company.child_ids or env.company:
    if property_remote_id := odoo_properties_mapping.get(property):
        if not (property_remote_id and (el := channex_properties_by_id.get(property_remote_id))):
            to_add_properties.append(property.id)

for property_channex_id in to_remove_properties:
    env.ref('booking_channex.requests_to_channex').with_context(method="DELETE", endpoint="properties/%s" % property_channex_id).run()

self.env['ir.cron']._commit_progress(remaining=2)

#GROUPS
all_channex_groups = env.ref('booking_channex.requests_to_channex').with_context(
    method="GET", endpoint="groups"
).run().json().get('data', {})

group_mapping = env['x_channex_mapping'].search([
    ('x_model_type', '=', 'group'),
    ('x_local_id', '=', env.company.id)
], limit=1)

if not all_channex_groups:
    to_add_groups.append(env.company.id)
if len(all_channex_groups) > 1:
    for el in all_channex_groups:
        if el.get("id") and el.get("id") != group_mapping.x_remote_id:
            to_remove_groups.append(el.get("id"))

self.env['ir.cron']._commit_progress(remaining=1)

#At the end so the order of creation is respected
env.ref('booking_channex.create_property_on_channex').with_context(active_ids=to_add_properties, active_model="res.company").run()
env.ref('booking_channex.create_room_on_channex').with_context(active_ids=to_add_rooms, active_model="product.product").run()
env.ref('booking_channex.create_rate_plan_on_channex').with_context(active_ids=to_add_rate_plans, active_model="x_rate_plan").run()

#Check the bookings too ?

self.env['ir.cron']._commit_progress(remaining=0)

rate_plans_to_create = []
pricelists = env.context.get('pricelists', False) or env['product.pricelist'].search([('x_published_on_channex', '=', True)])
products = env.context.get('products', False) or env['product.product'].search([('x_is_a_room_offer', '!=', False)])
existing_rate_plans = dict(env['x_rate_plan']._read_group(domain=[('x_variant_id', 'in', products.ids), ('x_pricelist_id', 'in', pricelists.ids)], groupby=['x_variant_id'], aggregates=['x_rate_plan_value_id:recordset']))
for pricelist in pricelists:
    for product in products:
        rates_already_applied = existing_rate_plans.get(product, False) or env['product.attribute.value']
        rate_plan_attribute_lines = product.attribute_line_ids.filtered(lambda line: line.attribute_id.x_accommodation_characteristic in ['rate_plan'])        
        x_rate_plan_falsy_rate = product.x_rate_plans_ids.filtered(lambda r: not r.x_rate_plan_value_id and r.x_pricelist_id.id == pricelist.id)
        rates_to_add = []
        if rate_plan_attribute_lines:
            rates_to_add = (rate_plan_attribute_lines.value_ids-rates_already_applied).ids
            x_rate_plan_falsy_rate.unlink()
            rates_to_remove = rates_already_applied-rate_plan_attribute_lines.value_ids
        else:
            if not x_rate_plan_falsy_rate:
                rates_to_add = [False]
            rates_to_remove = rates_already_applied
        for value in rates_to_add:
            rate_plans_to_create.append({
                'x_variant_id': product.id,
                'x_rate_plan_value_id': value,
                'x_pricelist_id': pricelist.id,
            })
        if rates_to_remove:
            product.x_rate_plans_ids.filtered(lambda r: r.x_rate_plan_value_id.id in rates_to_remove.ids).unlink()
env['x_rate_plan'].create(rate_plans_to_create)
